# [SYSTEM: LEGACY_TUI | STATUS: ARCHIVE | DO NOT EXECUTE]
"""
Confirmation gates for destructive operations.
Provides safety mechanisms to prevent accidental data loss.
"""
import time
from typing import Dict, List, Optional, Any, Callable
import sys
from dataclasses import dataclass
from enum import Enum
import asyncio
from rich.console import Console
from rich.prompt import Confirm, Prompt
from rich.table import Table
from rich.panel import Panel

console = Console()

class RiskLevel(Enum):
    """Risk levels for operations"""
    LOW = "LOW"
    MEDIUM = "MEDIUM"
    HIGH = "HIGH"
    CRITICAL = "CRITICAL"

@dataclass
class OperationInfo:
    """Information about an operation requiring confirmation"""
    operation_name: str
    description: str
    risk_level: RiskLevel
    affected_items: List[str]
    consequences: List[str]
    reversible: bool
    backup_available: bool
    estimated_time: str = "< 1 minute"
    # Optional extra context for display/logging
    context_data: Optional[Dict[str, Any]] = None

class ConfirmationGate:
    """
    Manages confirmation gates for destructive operations.
    Provides graduated confirmation based on risk level.
    """

    def __init__(self, enable_auto_confirm: bool = False):
        """
        Initialize confirmation gate system.

        Args:
            enable_auto_confirm: If True, automatically confirm LOW risk operations
        """
        # Allow headless auto-confirm for LOW risk via env var HEADLESS
        try:
            import os
            headless = os.getenv('HEADLESS', '').lower() in ('1', 'true', 'yes')
        except Exception:
            headless = False
        # Treat non-tty stdin as headless as well
        try:
            not_tty = not sys.stdin.isatty()
        except Exception:
            not_tty = False
        self.enable_auto_confirm = enable_auto_confirm or headless or not_tty
        self.confirmation_history: List[Dict[str, Any]] = []
        self.bypass_confirmations = False  # Emergency bypass for batch operations

    def require_confirmation(
        self,
        operation: OperationInfo,
        custom_prompt: Optional[str] = None
    ) -> bool:
        """
        Require confirmation for an operation based on its risk level.

        Args:
            operation: Operation information
            custom_prompt: Custom confirmation prompt

        Returns:
            True if user confirms, False otherwise
        """
        # Record the request
        confirmation_request = {
            'timestamp': time.time(),
            'operation': operation.operation_name,
            'risk_level': operation.risk_level.value,
            'confirmed': False
        }

        try:
            # Check for auto-confirm conditions
            if self._should_auto_confirm(operation):
                confirmation_request['confirmed'] = True
                confirmation_request['auto_confirmed'] = True
                self.confirmation_history.append(confirmation_request)
                return True

            # Check for bypass mode
            if self.bypass_confirmations:
                console.print(f"[yellow]⚠️ Bypassing confirmation for: {operation.operation_name}[/yellow]")
                confirmation_request['confirmed'] = True
                confirmation_request['bypassed'] = True
                self.confirmation_history.append(confirmation_request)
                return True

            # Display operation information
            self._display_operation_info(operation)

            # Get confirmation based on risk level
            confirmed = self._get_confirmation_by_risk_level(operation, custom_prompt)

            confirmation_request['confirmed'] = confirmed
            self.confirmation_history.append(confirmation_request)

            return confirmed

        except KeyboardInterrupt:
            console.print(f"\n[red]❌ Operation cancelled by user[/red]")
            confirmation_request['confirmed'] = False
            confirmation_request['cancelled'] = True
            self.confirmation_history.append(confirmation_request)
            return False

    def _should_auto_confirm(self, operation: OperationInfo) -> bool:
        """Check if operation should be auto-confirmed"""
        return (
            self.enable_auto_confirm and
            operation.risk_level == RiskLevel.LOW and
            operation.reversible and
            operation.backup_available
        )

    def _display_operation_info(self, operation: OperationInfo):
        """Display detailed operation information"""
        # Risk level styling
        risk_colors = {
            RiskLevel.LOW: "green",
            RiskLevel.MEDIUM: "yellow",
            RiskLevel.HIGH: "orange1",
            RiskLevel.CRITICAL: "red"
        }

        risk_icons = {
            RiskLevel.LOW: "✅",
            RiskLevel.MEDIUM: "⚠️",
            RiskLevel.HIGH: "🚨",
            RiskLevel.CRITICAL: "💀"
        }

        color = risk_colors[operation.risk_level]
        icon = risk_icons[operation.risk_level]

        # Create information table
        table = Table(show_header=False, box=None, padding=(0, 1))
        table.add_column("Field", style="bold")
        table.add_column("Value")

        table.add_row("Operation:", f"[bold]{operation.operation_name}[/bold]")
        table.add_row("Description:", operation.description)
        table.add_row("Risk Level:", f"[{color}]{icon} {operation.risk_level.value}[/{color}]")
        table.add_row("Reversible:", "✅ Yes" if operation.reversible else "❌ No")
        table.add_row("Backup Available:", "✅ Yes" if operation.backup_available else "❌ No")
        table.add_row("Estimated Time:", operation.estimated_time)

        # Extra contextual information (optional)
        if operation.context_data:
            try:
                items = [f"{k}: {v}" for k, v in list(operation.context_data.items())[:4]]
                table.add_row("Context:", " | ".join(items))
            except Exception:
                pass

        if operation.affected_items:
            table.add_row("Affected Items:", ", ".join(operation.affected_items[:3]))
            if len(operation.affected_items) > 3:
                table.add_row("", f"... and {len(operation.affected_items) - 3} more")

        if operation.consequences:
            table.add_row("Consequences:", "\n".join(f"• {c}" for c in operation.consequences))

        # Display in panel
        panel_title = f"{icon} Confirmation Required: {operation.operation_name}"
        panel = Panel(table, title=panel_title, border_style=color)
        console.print(panel)

    def _get_confirmation_by_risk_level(
        self,
        operation: OperationInfo,
        custom_prompt: Optional[str] = None
    ) -> bool:
        """Get confirmation based on operation risk level"""

        if operation.risk_level == RiskLevel.LOW:
            return self._confirm_low_risk(operation, custom_prompt)
        elif operation.risk_level == RiskLevel.MEDIUM:
            return self._confirm_medium_risk(operation, custom_prompt)
        elif operation.risk_level == RiskLevel.HIGH:
            return self._confirm_high_risk(operation, custom_prompt)
        elif operation.risk_level == RiskLevel.CRITICAL:
            return self._confirm_critical_risk(operation, custom_prompt)

        return False

    def _confirm_low_risk(self, operation: OperationInfo, custom_prompt: Optional[str]) -> bool:
        """Confirm low risk operation (simple yes/no)"""
        prompt = custom_prompt or f"Proceed with {operation.operation_name}?"
        return Confirm.ask(prompt, default=True)

    def _confirm_medium_risk(self, operation: OperationInfo, custom_prompt: Optional[str]) -> bool:
        """Confirm medium risk operation (explicit confirmation)"""
        prompt = custom_prompt or f"Are you sure you want to proceed with {operation.operation_name}?"
        confirmed = Confirm.ask(prompt, default=False)

        if confirmed and not operation.backup_available:
            console.print("[yellow]⚠️ No backup is available for this operation.[/yellow]")
            return Confirm.ask("Continue anyway?", default=False)

        return confirmed

    def _confirm_high_risk(self, operation: OperationInfo, custom_prompt: Optional[str]) -> bool:
        """Confirm high risk operation (double confirmation)"""
        # First confirmation
        prompt = custom_prompt or f"This is a HIGH RISK operation. Are you sure you want to {operation.operation_name}?"
        if not Confirm.ask(prompt, default=False):
            return False

        # Safety checks
        if not operation.reversible:
            console.print("[red]⚠️ This operation is NOT reversible![/red]")
            if not Confirm.ask("Do you understand this cannot be undone?", default=False):
                return False

        if not operation.backup_available:
            console.print("[red]⚠️ No backup is available![/red]")
            if not Confirm.ask("Continue without backup protection?", default=False):
                return False

        # Second confirmation
        return Confirm.ask(f"Final confirmation: Proceed with {operation.operation_name}?", default=False)

    def _confirm_critical_risk(self, operation: OperationInfo, custom_prompt: Optional[str]) -> bool:
        """Confirm critical risk operation (triple confirmation with typing)"""
        console.print(f"[red bold]🚨 CRITICAL OPERATION: {operation.operation_name.upper()}[/red bold]")

        # First confirmation
        if not Confirm.ask("This is a CRITICAL operation that may cause data loss. Continue?", default=False):
            return False

        # Safety check requirements
        safety_passed = True

        if not operation.reversible:
            console.print("[red bold]⚠️ IRREVERSIBLE OPERATION![/red bold]")
            safety_passed = False

        if not operation.backup_available:
            console.print("[red bold]⚠️ NO BACKUP PROTECTION![/red bold]")
            safety_passed = False

        if not safety_passed:
            console.print("[red]This operation fails safety requirements.[/red]")
            if not Confirm.ask("Override safety requirements?", default=False):
                return False

        # Typed confirmation
        confirmation_phrase = f"DELETE {operation.operation_name.upper()}"
        console.print(f"\n[red]To proceed, type exactly: [bold]{confirmation_phrase}[/bold][/red]")

        user_input = Prompt.ask("Confirmation phrase")
        if user_input != confirmation_phrase:
            console.print("[red]❌ Confirmation phrase incorrect. Operation cancelled.[/red]")
            return False

        # Final confirmation
        console.print("\n[red bold]FINAL WARNING: This operation may cause permanent data loss![/red bold]")
        return Confirm.ask("Are you absolutely certain you want to proceed?", default=False)

    def set_bypass_mode(self, enabled: bool, duration_seconds: Optional[float] = None):
        """
        Enable/disable bypass mode for batch operations.

        Args:
            enabled: Whether to enable bypass mode
            duration_seconds: Auto-disable after this many seconds
        """
        self.bypass_confirmations = enabled

        if enabled:
            console.print(f"[yellow]⚠️ Confirmation bypass mode enabled[/yellow]")
            if duration_seconds:
                # Schedule auto-disable
                async def auto_disable():
                    await asyncio.sleep(duration_seconds)
                    self.bypass_confirmations = False
                    console.print("[green]Confirmation bypass mode auto-disabled[/green]")

                asyncio.create_task(auto_disable())
        else:
            console.print("[green]Confirmation bypass mode disabled[/green]")

    def get_confirmation_history(self, limit: Optional[int] = None) -> List[Dict[str, Any]]:
        """Get recent confirmation history"""
        history = self.confirmation_history
        if limit:
            history = history[-limit:]
        return history

    def get_operation_stats(self) -> Dict[str, Any]:
        """Get statistics about confirmation usage"""
        if not self.confirmation_history:
            return {'total_requests': 0}

        total = len(self.confirmation_history)
        confirmed = sum(1 for req in self.confirmation_history if req['confirmed'])
        auto_confirmed = sum(1 for req in self.confirmation_history if req.get('auto_confirmed', False))
        bypassed = sum(1 for req in self.confirmation_history if req.get('bypassed', False))

        risk_levels = {}
        for req in self.confirmation_history:
            risk = req['risk_level']
            risk_levels[risk] = risk_levels.get(risk, 0) + 1

        return {
            'total_requests': total,
            'confirmed_count': confirmed,
            'confirmation_rate': confirmed / total if total > 0 else 0,
            'auto_confirmed_count': auto_confirmed,
            'bypassed_count': bypassed,
            'risk_level_distribution': risk_levels
        }

# Global confirmation gate instance
confirmation_gate = ConfirmationGate()

def _coerce_operation(info: Any) -> OperationInfo:
    """Helper to accept either OperationInfo or a dict-like and coerce safely."""
    if isinstance(info, OperationInfo):
        return info
    if isinstance(info, dict):
        # Minimal fields with safe defaults
        return OperationInfo(
            operation_name=info.get('operation_name', 'Operation'),
            description=info.get('description', ''),
            risk_level=info.get('risk_level', RiskLevel.LOW),
            affected_items=info.get('affected_items', []),
            consequences=info.get('consequences', []),
            reversible=info.get('reversible', False),
            backup_available=info.get('backup_available', False),
            estimated_time=info.get('estimated_time', '< 1 minute'),
            context_data=info.get('context_data')
        )
    raise TypeError("confirm_operation requires OperationInfo or dict")

def confirm_operation(operation_info: Any) -> bool:
    """Module-level helper to confirm an operation.

    Accepts OperationInfo or a dict with OperationInfo fields.
    """
    info = _coerce_operation(operation_info)
    return confirmation_gate.require_confirmation(info)

